// Enable/Disable 2FA for a user
app.post('/api/2fa/toggle', requireFullAuth, (req, res) => {
    const { enable } = req.body;
    const user = users.get(req.session.userId);

    if (!user) {
        return res.status(404).json({
            success: false,
            error: 'User not found.'
        });
    }

    user.twoFactorEnabled = Boolean(enable);

    return res.json({
        success: true,
        message: `Two-factor authentication ${user.twoFactorEnabled ? 'enabled' : 'disabled'}.`,
        twoFactorEnabled: user.twoFactorEnabled
    });
});

// Update phone number
app.post('/api/2fa/phone', requireFullAuth, (req, res) => {
    const { phoneNumber } = req.body;

    if (!phoneNumber || !/^\+\d{10,15}$/.test(phoneNumber)) {
        return res.status(400).json({
            success: false,
            error: 'Valid phone number in E.164 format is required (e.g., +1234567890).'
        });
    }

    const user = users.get(req.session.userId);

    if (!user) {
        return res.status(404).json({
            success: false,
            error: 'User not found.'
        });
    }

    user.phoneNumber = phoneNumber;

    const maskedPhone = phoneNumber.replace(/(\+\d{1,3})\d+(\d{4})/, '$1****$2');

    return res.json({
        success: true,
        message: `Phone number updated to ${maskedPhone}.`,
        phoneNumber: maskedPhone
    });
});

// Register a new user
app.post('/auth/register', (req, res) => {
    const { username, password, phoneNumber } = req.body;

    if (!username || !password || !phoneNumber) {
        return res.status(400).json({
            success: false,
            error: 'Username, password, and phone number are required.'
        });
    }

    if (!/^\+\d{10,15}$/.test(phoneNumber)) {
        return res.status(400).json({
            success: false,
            error: 'Phone number must be in E.164 format (e.g., +1234567890).'
        });
    }

    // Check for existing username
    for (const [id, user] of users.entries()) {
        if (user.username === username) {
            return res.status(409).json({
                success: false,
                error: 'Username already exists.'
            });
        }
    }

    const userId = `user_${crypto.randomUUID()}`;
    const newUser = {
        id: userId,
        username,
        password, // In production, hash with bcrypt
        phoneNumber,
        twoFactorEnabled: true
    };

    users.set(userId, newUser);

    const maskedPhone = phoneNumber.replace(/(\+\d{1,3})\d+(\d{4})/, '$1****$2');

    return res.status(201).json({
        success: true,
        message: 'User registered successfully with 2FA enabled.',
        user: {
            id: userId,
            username,
            phoneNumber: maskedPhone,
            twoFactorEnabled: true
        }
    });
});

// Logout
app.post('/auth/logout', (req, res) => {
    // Clean up any pending 2FA codes
    twoFactorStore.delete(req.session.id);

    req.session.destroy((err) => {
        if (err) {
            return res.status(500).json({
                success: false,
                error: 'Failed to logout.'
            });
        }

        res.clearCookie('connect.sid');
        return res.json({
            success: true,
            message: 'Logged out successfully.'
        });
    });
});

